/**
 * api.js — Simulated API service layer
 *
 * In production, replace these with real fetch/axios calls to your backend.
 * Each function mirrors the shape of a real REST API endpoint.
 *
 * Base URL example: https://api.shopkart.in/v1
 */

const BASE_URL = "https://api.shopkart.in/v1"; // Replace with real API base URL
const DEMO_MODE = true; // Set false to use real endpoints

/** Helper: simulate network delay */
const delay = ms => new Promise(resolve => setTimeout(resolve, ms));

/** Helper: simulate random failure (10% chance) for demo realism */
const mayFail = () => Math.random() < 0.1;

// ─────────────────────────────────────────────
// AUTH ENDPOINTS
// ─────────────────────────────────────────────

/**
 * POST /auth/check-email
 * Checks if an email address is already registered.
 * @param {string} email
 * @returns {{ available: boolean, message: string }}
 */
export async function checkEmailAvailability(email) {
  if (DEMO_MODE) {
    await delay(900);
    // Simulate "already registered" for this specific email
    if (email === "taken@example.com") {
      return {
        available: false,
        message: "This email is already registered."
      };
    }
    return {
      available: true,
      message: "Email is available."
    };
  }
  const res = await fetch(`${BASE_URL}/auth/check-email`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      email
    })
  });
  if (!res.ok) throw new Error("Failed to check email");
  return res.json();
}

/**
 * POST /auth/send-otp
 * Sends a one-time password to the user's mobile number.
 * @param {string} mobile  — e.g. "9876543210"
 * @param {string} countryCode — e.g. "+91"
 * @returns {{ success: boolean, otp?: string, expiresIn: number }}
 */
export async function sendOtp(mobile, countryCode) {
  if (DEMO_MODE) {
    await delay(1200);
    const otp = String(Math.floor(100000 + Math.random() * 900000));
    console.info(`[DEMO] OTP for ${countryCode}${mobile}: ${otp}`);
    // Return OTP in demo; real API would NEVER return OTP to client
    return {
      success: true,
      otp,
      expiresIn: 30
    };
  }
  const res = await fetch(`${BASE_URL}/auth/send-otp`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      mobile,
      countryCode
    })
  });
  if (!res.ok) throw new Error("Failed to send OTP");
  return res.json();
}

/**
 * POST /auth/verify-otp
 * Verifies the OTP entered by the user.
 * @param {string} mobile
 * @param {string} otp
 * @param {string} sessionToken — token returned from sendOtp in production
 * @returns {{ valid: boolean, message: string }}
 */
export async function verifyOtp(mobile, otp, sessionToken) {
  if (DEMO_MODE) {
    await delay(1000);
    // Accept the real generated OTP or "000000" as bypass
    const isValid = otp === sessionToken || otp === "000000";
    return {
      valid: isValid,
      message: isValid ? "OTP verified successfully." : "Invalid OTP. Please try again."
    };
  }
  const res = await fetch(`${BASE_URL}/auth/verify-otp`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      mobile,
      otp,
      sessionToken
    })
  });
  if (!res.ok) throw new Error("Failed to verify OTP");
  return res.json();
}

/**
 * POST /auth/register
 * Creates a new user account.
 * @param {object} userData
 * @returns {{ success: boolean, userId: string, token: string, message: string }}
 */
export async function registerUser(userData) {
  if (DEMO_MODE) {
    await delay(1500);
    if (mayFail()) throw new Error("Server error. Please try again.");
    return {
      success: true,
      userId: `USR_${Date.now()}`,
      token: `tok_demo_${Math.random().toString(36).slice(2)}`,
      message: "Account created successfully!"
    };
  }
  const res = await fetch(`${BASE_URL}/auth/register`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json"
    },
    body: JSON.stringify(userData)
  });
  if (!res.ok) {
    const err = await res.json();
    throw new Error(err.message || "Registration failed");
  }
  return res.json();
}

/**
 * POST /auth/google
 * OAuth registration/login via Google.
 * @returns {{ success: boolean, token: string, isNew: boolean }}
 */
export async function googleAuth() {
  if (DEMO_MODE) {
    await delay(800);
    return {
      success: true,
      token: "tok_google_demo",
      isNew: true
    };
  }
  // In production: trigger Google OAuth popup, then exchange code
  throw new Error("Google OAuth not configured");
}

